module RefModule (
    input clk,
    input nreset,
    input load,
    input [7:0] data,
    output [7:0] q );reg [7:0] unused_q_reg;

always @(posedge clk or negedge nreset) begin
    if (!nreset)
        unused_q_reg <= 8'b00000000;
    else if (load)
        unused_q_reg <= data;
end

assign q = unused_q_reg;

endmodule
